"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[119],{14505:e=>{e.exports=JSON.parse('{"functions":[{"name":"GetPosition","desc":"Returns the bullet\'s current world-space position using the analytic\\nkinematic formula. Always accurate to the current simulation time\\nregardless of when in the frame it is called.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":55,"path":"docs/HybridCast.lua"}},{"name":"GetVelocity","desc":"Returns the bullet\'s current velocity vector. The magnitude of this vector\\nis the current speed in studs per second.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":63,"path":"docs/HybridCast.lua"}},{"name":"GetAcceleration","desc":"Returns the constant acceleration vector for the active trajectory segment.\\nThis is the pre-computed sum of gravity and any extra acceleration \u2014 not\\n`workspace.Gravity` alone.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":72,"path":"docs/HybridCast.lua"}},{"name":"SetPosition","desc":"Teleports the bullet to a new world-space position without changing its\\nvelocity or acceleration. Opens a new trajectory segment if simulation\\ntime has already elapsed on the current one.","params":[{"name":"position","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":83,"path":"docs/HybridCast.lua"}},{"name":"SetVelocity","desc":"Changes the bullet\'s velocity to the given vector. Opens a new trajectory\\nsegment if needed.\\n\\n:::tip\\nCall [VetraCast:ResetBounceState] after a sharp velocity change to prevent\\nthe corner-trap detector from triggering on the new trajectory.\\n:::","params":[{"name":"velocity","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":96,"path":"docs/HybridCast.lua"}},{"name":"SetAcceleration","desc":"Replaces the bullet\'s constant acceleration for future simulation. Because\\nacceleration is constant within a segment, this always opens a new segment\\nunless the current one has zero elapsed time.","params":[{"name":"acceleration","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":105,"path":"docs/HybridCast.lua"}},{"name":"AddPosition","desc":"Translates the bullet by an offset in world space. Equivalent to\\n`SetPosition(GetPosition() + offset)`.","params":[{"name":"offset","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":113,"path":"docs/HybridCast.lua"}},{"name":"AddVelocity","desc":"Adds a delta to the bullet\'s current velocity. Useful for impulse effects\\nsuch as explosion knockback applied mid-flight.","params":[{"name":"delta","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":121,"path":"docs/HybridCast.lua"}},{"name":"AddAcceleration","desc":"Adds a delta to the bullet\'s constant acceleration. Useful for variable wind\\nor thrust that builds up over time via repeated calls.","params":[{"name":"delta","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":129,"path":"docs/HybridCast.lua"}},{"name":"ResetBounceState","desc":"Resets the corner-trap sentinel fields (`LastBounceTime`, `LastBounceNormal`,\\n`LastBouncePosition`) back to their initial values.\\n\\nCall this after any programmatic mid-flight velocity change (e.g. `SetVelocity`,\\n`AddVelocity`) that deliberately reverses or sharply redirects the bullet,\\notherwise the corner-trap detector may falsely terminate the cast on the\\nnext bounce.","params":[],"returns":[],"function_type":"method","source":{"line":142,"path":"docs/HybridCast.lua"}}],"properties":[{"name":"Alive","desc":"`true` while the cast is being simulated. Set to `false` as the very first\\naction in termination so re-entrant calls are no-ops.","lua_type":"boolean","readonly":true,"source":{"line":28,"path":"docs/HybridCast.lua"}},{"name":"Paused","desc":"When `true`, `_StepProjectile` skips this cast entirely. `TotalRuntime` does\\nnot advance, producing seamless resumption from the paused position when set\\nback to `false`.","lua_type":"boolean","source":{"line":37,"path":"docs/HybridCast.lua"}},{"name":"UserData","desc":"Free-form table for weapon-specific metadata. Shared with the linked\\n[BulletContext] and passed unchanged on every signal emission.","lua_type":"{[any]: any}","source":{"line":45,"path":"docs/HybridCast.lua"}}],"types":[],"name":"VetraCast","desc":"The internal representation of one in-flight projectile. Returned by\\n[Vetra:Fire] for callers that need to introspect initial state.\\n\\n:::warning\\nWeapon scripts should interact with [BulletContext] rather than `VetraCast`\\ndirectly. `VetraCast` exposes internal solver state \u2014 mutating it directly\\ncan produce physics errors that are difficult to debug.\\n\\nThe methods below (`GetPosition`, `SetVelocity`, etc.) are safe to call and are\\nthe intended way to read or modify a bullet mid-flight from within signal handlers.\\n:::","source":{"line":16,"path":"docs/HybridCast.lua"}}')}}]);